import org.springframework.data.repository.query.Param;
import org.springframework.stereotype.Repository;

@Repository
public interface WeeklyPlanRepository extends JpaRepository<WeeklyPlan, UUID> {

	Optional<WeeklyPlan> findByOwnerUserIdAndWeekStartDate(UUID ownerUserId, LocalDate weekStartDate);

	List<WeeklyPlan> findByTeamIdAndWeekStartDate(UUID teamId, LocalDate weekStartDate);

	List<WeeklyPlan> findByTeamIdOrderByWeekStartDateDesc(UUID teamId);

	List<WeeklyPlan> findByOwnerUserIdOrderByWeekStartDateDesc(UUID ownerUserId);

	List<WeeklyPlan> findByState(PlanState state);

	/** Used by the auto-lock job to find expired DRAFT plans. */
	List<WeeklyPlan> findByStateAndLockDeadlineBefore(PlanState state, Instant deadline);

	/**
	 * Used by the auto-reconcile job to find LOCKED plans past their reconcile-open
	 * time.
	 */
	List<WeeklyPlan> findByStateAndReconcileDeadlineBefore(PlanState state, Instant deadline);

	/**
	 * Used by the deadline reminder job to find DRAFT plans with lock due within a
	 * window.
	 */
	List<WeeklyPlan> findByStateAndLockDeadlineBetween(PlanState state, Instant from, Instant to);

	/**
	 * Used by the deadline reminder job to find RECONCILING plans with reconcile
	 * due within a window.
	 */
	List<WeeklyPlan> findByStateAndReconcileDeadlineBetween(PlanState state, Instant from, Instant to);

	boolean existsByOwnerUserIdAndWeekStartDate(UUID ownerUserId, LocalDate weekStartDate);

	/**
	 * Used by the scheduled read-model refresh to find all plans for the current
	 * week.
	 */
	List<WeeklyPlan> findByWeekStartDate(LocalDate weekStartDate);

	/** Used by the daily RAG sweep to find recently updated plans. */
	@Query("SELECT p FROM WeeklyPlan p WHERE p.updatedAt > :since")
	List<WeeklyPlan> findUpdatedSince(@Param("since") Instant since);
}

package com.weeklycommit.ai.provider;

/**
 * Result returned by an {@link AiProvider}.
 *
 * <p>
 * When {@code available} is {@code false}, all other fields are meaningless and
 * callers should propagate {@code aiAvailable: false} to their response without
 * failing the request.
 */
public record AiSuggestionResult(
		/** {@code false} when the provider is down or AI is disabled. */
		boolean available,
		/**
		 * JSON-serialised suggestion payload. Structure varies by
		 * {@link AiContext#suggestionType()}.
		 */
		String payload,
		/** Human-readable rationale explaining why the suggestion was made. */
		String rationale,
		/**
		 * Provider confidence in the primary suggestion [0.0, 1.0]. Used for RCDO
		 * suggestions to filter below the surfacing threshold.
		 */
		double confidence,
		/** Provider model identifier for audit and reproducibility. */
		String modelVersion,
		/**
		 * Prompt template version identifier for A/B testing (e.g.
		 * "commit-draft-assist-v1"). May be null for older results.
		 */
		String promptVersion) {

	/**
	 * Backwards-compatible constructor for callers that do not yet provide a prompt
	 * version.
	 */
	public AiSuggestionResult(boolean available, String payload, String rationale, double confidence,
			String modelVersion) {
		this(available, payload, rationale, confidence, modelVersion, null);
	}

	/** Convenience factory for an unavailable (degraded) result. */
	public static AiSuggestionResult unavailable() {
		return new AiSuggestionResult(false, "{}", "AI provider unavailable", 0.0, "none", null);
	}
}

