/**
 * AI API client functions for all AI-powered endpoints.
 */
import type { ApiClient } from "./client.js";

// ── Types ─────────────────────────────────────────────────────────────────────

export interface AiStatusResponse {
  aiEnabled: boolean;
  providerName: string;
  providerVersion: string;
  available: boolean;
}

export interface CommitDraftAssistRequest {
  userId: string;
  planId: string;
  commitId?: string | undefined;
  currentTitle: string;
  currentDescription?: string | undefined;
  currentSuccessCriteria?: string | undefined;
  currentEstimatePoints?: number | undefined;
  chessPiece?: string | undefined;
}

export interface CommitDraftAssistResponse {
  aiAvailable: boolean;
  suggestionId?: string;
  suggestedTitle?: string | null;
  suggestedDescription?: string | null;
  suggestedSuccessCriteria?: string | null;
  suggestedEstimatePoints?: number | null;
  /** Suggested chess piece. Non-null only when chessPiece was absent in the request. */
  suggestedChessPiece?: string | null;
  rationale?: string;
}

export interface CommitLintRequest {
  userId: string;
  planId: string;
}

export interface LintMessage {
  code: string;
  message: string;
  commitId?: string;
}

export interface CommitLintResponse {
  aiAvailable: boolean;
  suggestionId?: string;
  hardValidation: LintMessage[];
  softGuidance: LintMessage[];
  rationale?: string;
}

export interface RiskSignal {
  id: string;
  signalType: string;
  rationale: string;
  planId: string;
  commitId?: string | null;
  createdAt: string;
}

export interface PlanRiskSignalsResponse {
  aiAvailable: boolean;
  planId: string;
  signals: RiskSignal[];
}

// ── Reconcile Assist types ─────────────────────────────────────────────────

export interface ReconcileAssistRequest {
  planId: string;
  userId: string;
}

export interface CommitOutcomeSuggestion {
  commitId: string;
  commitTitle: string;
  suggestedOutcome: string;
  rationale: string;
}

export interface CarryForwardRecommendation {
  commitId: string;
  commitTitle: string;
  rationale: string;
}

export interface ReconcileAssistResponse {
  aiAvailable: boolean;
  suggestionId?: string;
  likelyOutcomes: CommitOutcomeSuggestion[];
  draftSummary?: string | null;
  carryForwardRecommendations: CarryForwardRecommendation[];
}

// ── RCDO Suggest types ────────────────────────────────────────────────────────

export interface RcdoSuggestRequest {
  planId: string;
  userId: string;
  /** Commit title used for semantic matching (required). */
  title: string;
  description?: string | undefined;
  chessPiece?: string | undefined;
}

export interface RcdoSuggestResponse {
  aiAvailable: boolean;
  /** True when a high-confidence (≥ 0.7) match was found. */
  suggestionAvailable: boolean;
  /** Stored suggestion id (null when unavailable or below threshold). */
  suggestionId?: string | null;
  /** Suggested RCDO node id. */
  suggestedRcdoNodeId?: string | null;
  /** Display title of the suggested node. */
  rcdoTitle?: string | null;
  /** Confidence score [0.0, 1.0]. */
  confidence?: number;
  /** Human-readable rationale for the suggestion. */
  rationale?: string | null;
}

export type FeedbackAction = "ACCEPTED" | "DISMISSED" | "EDITED";

export interface AiFeedbackRequest {
  suggestionId: string;
  userId: string;
  action: FeedbackAction;
  notes?: string;
}

// ── Manager AI Summary types ──────────────────────────────────────────────────

export interface ManagerAiSummaryResponse {
  aiAvailable: boolean;
  /** Stored suggestion id for feedback (null when unavailable). */
  suggestionId?: string | null;
  teamId: string;
  weekStart: string;
  /** Prose summary of the team week. Null when aiAvailable=false. */
  summaryText?: string | null;
  /** RCDO branch titles with highest planned commitment this week. */
  topRcdoBranches: string[];
  /** Unresolved exception ids (cited objects). */
  unresolvedExceptionIds: string[];
  /** Textual carry-forward patterns (cited from plan data). */
  carryForwardPatterns: string[];
  /** Work item ids for King/Queen commits currently BLOCKED (cited objects). */
  criticalBlockedItemIds: string[];
  modelVersion?: string | null;
}

// ── API factory ───────────────────────────────────────────────────────────────

export function createAiApi(client: ApiClient, actorUserId: string) {
  const actorHeader = { "X-Actor-User-Id": actorUserId };

  return {
    /** GET /api/ai/status — provider health/availability check. */
    getStatus: (): Promise<AiStatusResponse> =>
      client.get("/ai/status"),

    /** POST /api/ai/commit-draft-assist — get draft improvement suggestions. */
    commitDraftAssist: (
      request: CommitDraftAssistRequest,
    ): Promise<CommitDraftAssistResponse> =>
      client.post("/ai/commit-draft-assist", request),

    /**
     * Convenience helper for freeform "describe → structure" commit creation.
     * Sends the freeform text as currentTitle and omits chessPiece so the backend
     * can infer suggestedChessPiece.
     */
    commitFromFreeform: (
      planId: string,
      userId: string,
      freeformText: string,
    ): Promise<CommitDraftAssistResponse> =>
      client.post("/ai/commit-draft-assist", {
        planId,
        userId,
        currentTitle: freeformText,
      }),

    /** POST /api/ai/commit-lint — run commit quality lint on a plan. */
    commitLint: (request: CommitLintRequest): Promise<CommitLintResponse> =>
      client.post("/ai/commit-lint", request),

    /** GET /api/plans/{id}/risk-signals — risk signals for a plan. */
    getRiskSignals: (planId: string): Promise<PlanRiskSignalsResponse> =>
      client.get(`/plans/${encodeURIComponent(planId)}/risk-signals`, {
        headers: actorHeader,
      }),

    /** POST /api/ai/reconcile-assist — get reconciliation suggestions. */
    reconcileAssist: (
      request: ReconcileAssistRequest,
    ): Promise<ReconcileAssistResponse> =>
      client.post("/ai/reconcile-assist", request),

    /** POST /api/ai/feedback — record thumbs up/down on a suggestion. */
    recordFeedback: (request: AiFeedbackRequest): Promise<void> =>
      client.post("/ai/feedback", request),

    /**
     * POST /api/ai/rcdo-suggest — suggest a primary RCDO node for a commit
     * being authored. Only returns a suggestion when confidence ≥ 0.7.
     * Never auto-links — caller must present and allow user to accept/dismiss.
     */
    rcdoSuggest: (request: RcdoSuggestRequest): Promise<RcdoSuggestResponse> =>
      client.post("/ai/rcdo-suggest", request),

    /**
     * GET /api/teams/{id}/week/{weekStart}/ai-summary —
     * AI-generated manager team summary for the given team and week.
     *
     * @param teamId    team UUID string
     * @param weekStart ISO date string (YYYY-MM-DD) for the Monday of the week
     */
    getTeamAiSummary: (
      teamId: string,
      weekStart: string,
    ): Promise<ManagerAiSummaryResponse> =>
      client.get(
        `/teams/${encodeURIComponent(teamId)}/week/${encodeURIComponent(weekStart)}/ai-summary`,
        { headers: actorHeader },
      ),
  };
}

export type AiApi = ReturnType<typeof createAiApi>;

/**
 * React hooks for AI API endpoints.
 */
import { useMemo, useState, useEffect, useRef } from "react";
import { useHostBridge } from "../host/HostProvider.js";
import { createApiClient } from "./client.js";
import { useQuery, type QueryState } from "./hooks.js";
import { createAiApi, type AiApi, type AiStatusResponse, type PlanRiskSignalsResponse, type ReconcileAssistResponse, type ManagerAiSummaryResponse } from "./aiApi.js";
import { createWhatIfApi, type WhatIfApi } from "./whatIfApi.js";

/** Returns a stable WhatIfApi instance bound to the current user's auth token. */
export function useWhatIfApi(): WhatIfApi {
  const bridge = useHostBridge();
  const { authToken, authenticatedUser } = bridge.context;
  return useMemo(() => {
    const client = createApiClient({
      baseUrl: "/api",
      getAuthToken: () => bridge.context.authToken,
    });
    return createWhatIfApi(client, authenticatedUser.id);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [authToken, authenticatedUser.id]);
}

/** Returns a stable AiApi instance bound to the current user's auth token. */
export function useAiApi(): AiApi {
  const bridge = useHostBridge();
  const { authToken, authenticatedUser } = bridge.context;
  return useMemo(() => {
    const client = createApiClient({
      baseUrl: "/api",
      getAuthToken: () => bridge.context.authToken,
    });
    return createAiApi(client, authenticatedUser.id);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [authToken, authenticatedUser.id]);
}

/** Fetches the AI provider status. */
export function useAiStatus(): QueryState<AiStatusResponse> {
  const api = useAiApi();
  return useQuery<AiStatusResponse>("ai-status", () => api.getStatus());
}

/** Fetches risk signals for a specific plan. */
export function useRiskSignals(
  planId: string | null,
): QueryState<PlanRiskSignalsResponse> {
  const api = useAiApi();
  return useQuery<PlanRiskSignalsResponse>(
    `risk-signals-${planId ?? "none"}`,
    () => {
      if (!planId) return Promise.reject(new Error("No plan ID"));
      return api.getRiskSignals(planId);
    },
    { enabled: planId != null },
  );
}

/**
 * Fetches the AI-generated manager team summary for the given team and week.
 *
 * @param teamId    team UUID string, or `null` to skip fetching
 * @param weekStart ISO date string (YYYY-MM-DD)
 */
export function useManagerAiSummary(
  teamId: string | null,
  weekStart: string,
): QueryState<ManagerAiSummaryResponse> {
  const api = useAiApi();
  return useQuery<ManagerAiSummaryResponse>(
    `manager-ai-summary-${teamId ?? "none"}-${weekStart}`,
    () => {
      if (!teamId) return Promise.reject(new Error("No team ID"));
      return api.getTeamAiSummary(teamId, weekStart);
    },
    { enabled: teamId != null },
  );
}

/**
 * Auto-fetches AI reconciliation suggestions when a plan enters RECONCILING
 * state. Runs once per planId (tracked by ref). Falls back silently if AI
 * is unavailable — callers must handle `data === undefined`.
 *
 * @param planId       Plan UUID string, or null/undefined when not yet known.
 * @param userId       Authenticated user ID for the reconcile-assist request.
 * @param enabled      Set to `true` only when the plan is in RECONCILING state.
 */
export function useAutoReconcileAssist(
  planId: string | null | undefined,
  userId: string,
  enabled: boolean,
): { data: ReconcileAssistResponse | undefined; loading: boolean; error: string | null } {
  const aiApi = useAiApi();
  const [data, setData] = useState<ReconcileAssistResponse | undefined>(undefined);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  // Track which planId we've already fetched for so we don't re-fetch on re-renders.
  const fetchedForRef = useRef<string | null>(null);

  useEffect(() => {
    if (!enabled || !planId) return;
    if (fetchedForRef.current === planId) return;
    fetchedForRef.current = planId;

    let cancelled = false;
    setLoading(true);
    setError(null);

    aiApi
      .reconcileAssist({ planId, userId })
      .then((response) => {
        if (cancelled) return;
        if (response.aiAvailable) {
          setData(response);
        }
        setLoading(false);
      })
      .catch(() => {
        if (cancelled) return;
        // Graceful silent fallback — AI unavailable or errored.
        setError("AI suggestions unavailable");
        setLoading(false);
      });

    return () => {
      cancelled = true;
    };
    // aiApi is a new object each render but is memoised inside useAiApi by authToken.
    // Intentionally omitting it from deps to avoid re-fetching on unrelated renders.
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [planId, userId, enabled]);

  return { data, loading, error };
}

/**
 * WhatIfPanel — interactive what-if planner for hypothetical commit mutations.
 *
 * Lets users queue ADD / REMOVE / MODIFY mutations, simulate their impact
 * against the plan (always deterministic) and optionally view an AI narrative
 * (shown only when narrative is non-null — degrades gracefully when AI is down).
 *
 * Important: this panel does NOT gate on AI availability — the simulation is
 * backend rule-based logic that works without a live LLM.
 */
import { useState, useCallback } from "react";
import { Sparkles, Loader2, ChevronUp, Plus, X } from "lucide-react";
import { Button } from "../ui/Button.js";
import { Badge } from "../ui/Badge.js";
import { Card, CardContent, CardHeader, CardTitle } from "../ui/Card.js";
import { cn } from "../../lib/utils.js";
import { useWhatIfApi } from "../../api/aiHooks.js";
import { useHostBridge } from "../../host/HostProvider.js";
import type { CommitResponse } from "../../api/planTypes.js";
import type {
  WhatIfMutation,
  WhatIfMutationAction,
  WhatIfResponse,
} from "../../api/whatIfApi.js";

// ── Constants ─────────────────────────────────────────────────────────────────

const CHESS_PIECES = ["KING", "QUEEN", "ROOK", "BISHOP", "KNIGHT", "PAWN"] as const;
const ESTIMATE_POINTS = [1, 2, 3, 5, 8] as const;

// ── Types ─────────────────────────────────────────────────────────────────────

type ModifyField = "estimatePoints" | "chessPiece" | "rcdoNodeId";

export interface WhatIfPanelProps {
  planId: string;
  currentCommits: ReadonlyArray<CommitResponse>;
}

// ── Component ─────────────────────────────────────────────────────────────────

export function WhatIfPanel({ planId, currentCommits }: WhatIfPanelProps) {
  const api = useWhatIfApi();
  const bridge = useHostBridge();
  const userId = bridge.context.authenticatedUser.id;

  const [isExpanded, setIsExpanded] = useState(false);
  const [mutations, setMutations] = useState<WhatIfMutation[]>([]);
  const [result, setResult] = useState<WhatIfResponse | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // ── Mutation form state ───────────────────────────────────────────────────
  const [action, setAction] = useState<WhatIfMutationAction>("ADD_COMMIT");

  // ADD_COMMIT fields
  const [addTitle, setAddTitle] = useState("");
  const [addChessPiece, setAddChessPiece] = useState<string>("PAWN");
  const [addPoints, setAddPoints] = useState<string>("");

  // REMOVE_COMMIT fields
  const [removeCommitId, setRemoveCommitId] = useState<string>("");

  // MODIFY_COMMIT fields
  const [modifyCommitId, setModifyCommitId] = useState<string>("");
  const [modifyField, setModifyField] = useState<ModifyField>("estimatePoints");
  const [modifyValue, setModifyValue] = useState<string>("");

  // ── Handlers ─────────────────────────────────────────────────────────────

  const handleQueueMutation = useCallback(() => {
    if (action === "ADD_COMMIT") {
      if (!addTitle.trim()) return;
      const parsedPoints = addPoints
        ? parseInt(addPoints, 10)
        : undefined;
      const mutation: WhatIfMutation = {
        action: "ADD_COMMIT",
        title: addTitle.trim(),
        chessPiece: addChessPiece,
        ...(parsedPoints !== undefined && !isNaN(parsedPoints)
          ? { estimatePoints: parsedPoints }
          : {}),
      };
      setMutations((prev) => [...prev, mutation]);
      setAddTitle("");
      setAddPoints("");
    } else if (action === "REMOVE_COMMIT") {
      if (!removeCommitId) return;
      setMutations((prev) => [
        ...prev,
        { action: "REMOVE_COMMIT", commitId: removeCommitId },
      ]);
      setRemoveCommitId("");
    } else if (action === "MODIFY_COMMIT") {
      if (!modifyCommitId || !modifyValue.trim()) return;
      const mutation: WhatIfMutation = {
        action: "MODIFY_COMMIT",
        commitId: modifyCommitId,
        ...(modifyField === "estimatePoints"
          ? { estimatePoints: parseInt(modifyValue, 10) }
          : {}),
        ...(modifyField === "chessPiece" ? { chessPiece: modifyValue } : {}),
        ...(modifyField === "rcdoNodeId" ? { rcdoNodeId: modifyValue } : {}),
      };
      setMutations((prev) => [...prev, mutation]);
      setModifyValue("");
    }
  }, [
    action,
    addTitle,
    addChessPiece,
    addPoints,
    removeCommitId,
    modifyCommitId,
    modifyField,
    modifyValue,
  ]);

  const handleSimulate = useCallback(async () => {
    if (mutations.length === 0) return;
    setLoading(true);
    setError(null);
    setResult(null);
    try {
      const response = await api.simulate({
        planId,
        userId,
        hypotheticalChanges: mutations,
      });
      setResult(response);
    } catch {
      setError("Simulation failed. Please try again.");
    } finally {
      setLoading(false);
    }
  }, [api, planId, userId, mutations]);

  // ── Collapsed state ───────────────────────────────────────────────────────

  if (!isExpanded) {
    return (
      <Button
        variant="ghost"
        size="sm"
        onClick={() => setIsExpanded(true)}
        className="self-start text-primary hover:text-primary/80 border border-dashed border-primary/30"
        data-testid="whatif-expand-btn"
      >
        <Sparkles className="h-3.5 w-3.5 mr-1.5" aria-hidden="true" />
        🔮 What-If Planner
      </Button>
    );
  }

  // ── Expanded state ────────────────────────────────────────────────────────

  return (
    <Card data-testid="whatif-panel">
      <CardHeader>
        <CardTitle className="flex items-center gap-2 text-sm">
          <Sparkles className="h-4 w-4 text-primary" aria-hidden="true" />
          What-If Planner
        </CardTitle>
        <Button
          variant="ghost"
          size="icon"
          onClick={() => setIsExpanded(false)}
          className="h-7 w-7"
          aria-label="Collapse what-if planner"
          data-testid="whatif-collapse-btn"
        >
          <ChevronUp className="h-4 w-4" />
        </Button>
      </CardHeader>

      <CardContent className="flex flex-col gap-4">
        {/* ── Mutation form ─────────────────────────────────────────────── */}
        <div className="flex flex-col gap-3">
          {/* Action tabs */}
          <div className="flex gap-1.5" role="group" aria-label="Mutation type">
            {(
              [
                "ADD_COMMIT",
                "REMOVE_COMMIT",
                "MODIFY_COMMIT",
              ] as WhatIfMutationAction[]
            ).map((a) => (
              <Button
                key={a}
                variant={action === a ? "primary" : "secondary"}
                size="sm"
                onClick={() => setAction(a)}
                data-testid={`whatif-action-${a}`}
              >
                {a === "ADD_COMMIT"
                  ? "+ Add"
                  : a === "REMOVE_COMMIT"
                    ? "− Remove"
                    : "✎ Modify"}
              </Button>
            ))}
          </div>

          {/* ADD_COMMIT inputs */}
          {action === "ADD_COMMIT" && (
            <div className="flex flex-col gap-2">
              <input
                type="text"
                placeholder="Commit title (required)"
                value={addTitle}
                onChange={(e) => setAddTitle(e.target.value)}
                className="rounded-default border border-border px-2 py-1.5 text-sm bg-background text-foreground w-full"
                data-testid="whatif-add-title"
                aria-label="Hypothetical commit title"
              />
              <div className="flex gap-2">
                <select
                  value={addChessPiece}
                  onChange={(e) => setAddChessPiece(e.target.value)}
                  className="rounded-default border border-border px-2 py-1.5 text-sm bg-background text-foreground"
                  data-testid="whatif-add-chess"
                  aria-label="Chess piece"
                >
                  {CHESS_PIECES.map((p) => (
                    <option key={p} value={p}>
                      {p}
                    </option>
                  ))}
                </select>
                <select
                  value={addPoints}
                  onChange={(e) => setAddPoints(e.target.value)}
                  className="rounded-default border border-border px-2 py-1.5 text-sm bg-background text-foreground"
                  data-testid="whatif-add-points"
                  aria-label="Estimate points"
                >
                  <option value="">Points…</option>
                  {ESTIMATE_POINTS.map((p) => (
                    <option key={p} value={String(p)}>
                      {p} pts
                    </option>
                  ))}
                </select>
              </div>
            </div>
          )}

          {/* REMOVE_COMMIT input */}
          {action === "REMOVE_COMMIT" && (
            <select
              value={removeCommitId}
              onChange={(e) => setRemoveCommitId(e.target.value)}
              className="rounded-default border border-border px-2 py-1.5 text-sm bg-background text-foreground"
              data-testid="whatif-remove-select"
              aria-label="Select commit to remove"
            >
              <option value="">Select commit to remove…</option>
              {currentCommits.map((c) => (
                <option key={c.id} value={c.id}>
                  {c.title}
                </option>
              ))}
            </select>
          )}

          {/* MODIFY_COMMIT inputs */}
          {action === "MODIFY_COMMIT" && (
            <div className="flex flex-col gap-2">
              <select
                value={modifyCommitId}
                onChange={(e) => setModifyCommitId(e.target.value)}
                className="rounded-default border border-border px-2 py-1.5 text-sm bg-background text-foreground"
                data-testid="whatif-modify-commit-select"
                aria-label="Select commit to modify"
              >
                <option value="">Select commit to modify…</option>
                {currentCommits.map((c) => (
                  <option key={c.id} value={c.id}>
                    {c.title}
                  </option>
                ))}
              </select>
              <div className="flex gap-2">
                <select
                  value={modifyField}
                  onChange={(e) =>
                    setModifyField(e.target.value as ModifyField)
                  }
                  className="rounded-default border border-border px-2 py-1.5 text-sm bg-background text-foreground"
                  data-testid="whatif-modify-field-select"
                  aria-label="Field to modify"
                >
                  <option value="estimatePoints">Estimate Points</option>
                  <option value="chessPiece">Chess Piece</option>
                  <option value="rcdoNodeId">RCDO Node ID</option>
                </select>
                {modifyField === "estimatePoints" ? (
                  <select
                    value={modifyValue}
                    onChange={(e) => setModifyValue(e.target.value)}
                    className="rounded-default border border-border px-2 py-1.5 text-sm bg-background text-foreground"
                    data-testid="whatif-modify-value-points"
                    aria-label="New estimate points"
                  >
                    <option value="">Points…</option>
                    {ESTIMATE_POINTS.map((p) => (
                      <option key={p} value={String(p)}>
                        {p} pts
                      </option>
                    ))}
                  </select>
                ) : modifyField === "chessPiece" ? (
                  <select
                    value={modifyValue}
                    onChange={(e) => setModifyValue(e.target.value)}
                    className="rounded-default border border-border px-2 py-1.5 text-sm bg-background text-foreground"
                    data-testid="whatif-modify-value-chess"
                    aria-label="New chess piece"
                  >
                    <option value="">Piece…</option>
                    {CHESS_PIECES.map((p) => (
                      <option key={p} value={p}>
                        {p}
                      </option>
                    ))}
                  </select>
                ) : (
                  <input
                    type="text"
                    placeholder="RCDO Node ID (UUID)"
                    value={modifyValue}
                    onChange={(e) => setModifyValue(e.target.value)}
                    className="rounded-default border border-border px-2 py-1.5 text-sm bg-background text-foreground flex-1"
                    data-testid="whatif-modify-value-input"
                    aria-label="New RCDO node ID"
                  />
                )}
              </div>
            </div>
          )}

          <Button
            variant="secondary"
            size="sm"
            onClick={handleQueueMutation}
            className="self-start"
            data-testid="whatif-queue-btn"
          >
            <Plus className="h-3.5 w-3.5 mr-1" aria-hidden="true" />
            Queue Mutation
          </Button>
        </div>

        {/* ── Queued mutations list ──────────────────────────────────────── */}
        {mutations.length > 0 && (
          <div className="flex flex-col gap-1.5" data-testid="whatif-mutation-list">
            <p className="m-0 text-xs font-semibold text-muted uppercase tracking-wider">
              Queued Mutations ({mutations.length})
            </p>
            {mutations.map((m, i) => {
              const commitLabel =
                currentCommits.find((c) => c.id === m.commitId)?.title ??
                m.commitId ??
                "";
              return (
                <div
                  key={i}
                  className="flex items-center justify-between gap-2 rounded-sm border border-border px-2.5 py-1.5 text-xs"
                  data-testid={`whatif-mutation-${i}`}
                >
                  <span className="flex items-center gap-1.5 flex-1 min-w-0 truncate">
                    <Badge
                      variant="default"
                      className="text-[0.6rem] shrink-0"
                    >
                      {m.action}
                    </Badge>
                    <span className="truncate">
                      {m.action === "ADD_COMMIT" ? m.title : commitLabel}
                    </span>
                  </span>
                  <Button
                    variant="ghost"
                    size="icon"
                    onClick={() =>
                      setMutations((prev) => prev.filter((_, j) => j !== i))
                    }
                    className="h-5 w-5 shrink-0"
                    aria-label={`Remove mutation ${i + 1}`}
                    data-testid={`whatif-remove-mutation-${i}`}
                  >
                    <X className="h-3 w-3" />
                  </Button>
                </div>
              );
            })}
            <Button
              variant="ghost"
              size="sm"
              onClick={() => setMutations([])}
              className="self-start text-xs text-muted"
              data-testid="whatif-clear-mutations-btn"
            >
              Clear all
            </Button>
          </div>
        )}

        {/* ── Simulate button ────────────────────────────────────────────── */}
        <Button
          variant="primary"
          size="sm"
          onClick={() => void handleSimulate()}
          disabled={loading || mutations.length === 0}
          className="self-start"
          data-testid="whatif-simulate-btn"
        >
          {loading ? (
            <>
              <Loader2
                className="h-3.5 w-3.5 mr-1.5 animate-spin"
                aria-hidden="true"
              />
              Simulating…
            </>
          ) : (
            <>
              <Sparkles className="h-3.5 w-3.5 mr-1.5" aria-hidden="true" />
              Simulate
            </>
          )}
        </Button>

        {/* ── Error ─────────────────────────────────────────────────────── */}
        {error && (
          <div
            className="rounded-default border border-danger/30 bg-danger/5 px-3 py-2 text-xs text-danger"
            data-testid="whatif-error"
            role="alert"
          >
            {error}
          </div>
        )}

        {/* ── Results ───────────────────────────────────────────────────── */}
        {result && (
          <div className="flex flex-col gap-3 border-t border-border pt-3" data-testid="whatif-results">
            {/* Simulation unavailable */}
            {!result.available && (
              <div
                className="rounded-default border border-neutral-300 bg-neutral-100 px-3 py-2 text-xs text-muted"
                data-testid="whatif-unavailable"
              >
                Simulation is currently unavailable.
              </div>
            )}

            {result.available &&
              result.currentState &&
              result.projectedState && (
                <>
                  {/* Capacity impact */}
                  <div data-testid="whatif-capacity">
                    <p className="m-0 mb-1 text-xs font-semibold text-muted uppercase tracking-wider">
                      Capacity Impact
                    </p>
                    <div className="flex items-center gap-2 text-sm flex-wrap">
                      <span>{result.currentState.totalPoints} pts</span>
                      <span className="text-muted" aria-hidden="true">
                        →
                      </span>
                      <span
                        className={cn(
                          "font-semibold",
                          result.projectedState.totalPoints >
                            result.currentState.capacityBudget
                            ? "text-danger"
                            : "text-success",
                        )}
                      >
                        {result.projectedState.totalPoints} pts
                      </span>
                      <span className="text-xs text-muted">
                        (budget: {result.currentState.capacityBudget} pts,{" "}
                        <span
                          className={cn(
                            result.capacityDelta > 0
                              ? "text-warning"
                              : result.capacityDelta < 0
                                ? "text-success"
                                : "text-muted",
                          )}
                        >
                          {result.capacityDelta > 0 ? "+" : ""}
                          {result.capacityDelta}
                        </span>
                        )
                      </span>
                    </div>
                  </div>

                  {/* Risk delta */}
                  {result.riskDelta &&
                    (result.riskDelta.newRisks.length > 0 ||
                      result.riskDelta.resolvedRisks.length > 0) && (
                      <div data-testid="whatif-risk-delta">
                        <p className="m-0 mb-1 text-xs font-semibold text-muted uppercase tracking-wider">
                          Risk Changes
                        </p>
                        <div className="flex flex-col gap-1">
                          {result.riskDelta.newRisks.map((r) => (
                            <div
                              key={r}
                              className="flex items-center gap-1.5 text-xs text-danger"
                            >
                              <span aria-hidden="true">⚠</span>
                              <span>New:</span>
                              <Badge
                                variant="default"
                                className="text-[0.6rem] bg-danger/10 text-danger border-danger/20"
                              >
                                {r}
                              </Badge>
                            </div>
                          ))}
                          {result.riskDelta.resolvedRisks.map((r) => (
                            <div
                              key={r}
                              className="flex items-center gap-1.5 text-xs text-success"
                            >
                              <span aria-hidden="true">✓</span>
                              <span>Resolved:</span>
                              <Badge
                                variant="default"
                                className="text-[0.6rem] bg-success/10 text-success border-success/20"
                              >
                                {r}
                              </Badge>
                            </div>
                          ))}
                        </div>
                      </div>
                    )}

                  {/* RCDO coverage changes */}
                  {result.rcdoCoverageChanges &&
                    result.rcdoCoverageChanges.length > 0 && (
                      <div data-testid="whatif-coverage-changes">
                        <p className="m-0 mb-1 text-xs font-semibold text-muted uppercase tracking-wider">
                          RCDO Coverage Changes
                        </p>
                        <div className="flex flex-col gap-1">
                          {result.rcdoCoverageChanges.map((c) => (
                            <div
                              key={c.rcdoNodeId}
                              className="flex items-center gap-2 text-xs"
                            >
                              <span className="font-mono text-muted text-[0.65rem] truncate max-w-[8rem]">
                                {c.rcdoTitle ??
                                  c.rcdoNodeId.slice(0, 8) + "…"}
                              </span>
                              <span>{c.beforePoints} pts</span>
                              <span className="text-muted" aria-hidden="true">
                                →
                              </span>
                              <span
                                className={cn(
                                  "font-semibold",
                                  c.afterPoints > c.beforePoints
                                    ? "text-success"
                                    : "text-danger",
                                )}
                              >
                                {c.afterPoints} pts
                              </span>
                              <span
                                className={cn(
                                  "text-[0.65rem]",
                                  c.afterPoints > c.beforePoints
                                    ? "text-success"
                                    : "text-danger",
                                )}
                              >
                                (
                                {c.afterPoints - c.beforePoints > 0 ? "+" : ""}
                                {c.afterPoints - c.beforePoints})
                              </span>
                            </div>
                          ))}
                        </div>
                      </div>
                    )}

                  {/* AI narrative — shown only when narrative is non-null */}
                  {result.narrative && (
                    <div
                      className="rounded-default border border-primary/20 bg-primary/5 px-3 py-2.5"
                      data-testid="whatif-narrative"
                    >
                      <p className="m-0 mb-1.5 text-xs font-semibold text-primary uppercase tracking-wider flex items-center gap-1">
                        <Sparkles className="h-3 w-3" aria-hidden="true" />
                        AI Insight
                      </p>
                      <p className="m-0 text-sm leading-relaxed">
                        {result.narrative}
                      </p>
                      {result.recommendation && (
                        <p className="m-0 mt-2 text-xs text-muted italic">
                          💡 {result.recommendation}
                        </p>
                      )}
                    </div>
                  )}
                </>
              )}
          </div>
        )}
      </CardContent>
    </Card>
  );
}

/**
 * Thumbs up / thumbs down feedback buttons for AI suggestions.
 * Records feedback via POST /api/ai/feedback.
 */
import { useState, useCallback } from "react";
import { ThumbsUp, ThumbsDown } from "lucide-react";
import { Button } from "../ui/Button.js";
import { cn } from "../../lib/utils.js";
import { useAiApi } from "../../api/aiHooks.js";
import { useHostBridge } from "../../host/HostProvider.js";
import type { FeedbackAction } from "../../api/aiApi.js";

interface AiFeedbackButtonsProps {
  suggestionId: string;
  className?: string;
}

export function AiFeedbackButtons({ suggestionId, className }: AiFeedbackButtonsProps) {
  const aiApi = useAiApi();
  const bridge = useHostBridge();
  const userId = bridge.context.authenticatedUser.id;
  const [submitted, setSubmitted] = useState<FeedbackAction | null>(null);

  const handleFeedback = useCallback(
    async (action: FeedbackAction) => {
      try {
        await aiApi.recordFeedback({ suggestionId, userId, action });
        setSubmitted(action);
      } catch {
        // Non-critical — don't block the UI
      }
    },
    [aiApi, suggestionId, userId],
  );

  if (submitted) {
    return (
      <span className={cn("text-xs text-muted italic", className)}>
        {submitted === "ACCEPTED" ? "Thanks! 👍" : "Noted 👎"}
      </span>
    );
  }

  return (
    <span className={cn("inline-flex gap-1", className)}>
      <Button
        variant="ghost"
        size="icon"
        onClick={() => void handleFeedback("ACCEPTED")}
        aria-label="Helpful suggestion"
        className="h-6 w-6 text-muted hover:text-foreground"
        data-testid="ai-feedback-accept"
      >
        <ThumbsUp className="h-3.5 w-3.5" />
      </Button>
      <Button
        variant="ghost"
        size="icon"
        onClick={() => void handleFeedback("DISMISSED")}
        aria-label="Not helpful"
        className="h-6 w-6 text-muted hover:text-foreground"
        data-testid="ai-feedback-dismiss"
      >
        <ThumbsDown className="h-3.5 w-3.5" />
      </Button>
    </span>
  );
}

package com.weeklycommit.domain.enums;

public enum CommitOutcome {
	ACHIEVED, PARTIALLY_ACHIEVED, NOT_ACHIEVED, CANCELED
}

package com.weeklycommit.ai.evidence;

import java.time.LocalDate;
import java.util.List;
import java.util.Map;
import java.util.UUID;

/**
 * A structured evidence bundle assembled from multiple retrieval strategies.
 * Passed to the LLM as grounded context — the model synthesises only from this
 * bundle, never from its own knowledge.
 *
 * <p>
 * Also returned to the frontend so the UI can render an evidence drawer showing
 * exactly what the AI used to produce its answer.
 */
public record StructuredEvidence(SqlFacts sqlFacts, LineageChain lineage, List<SemanticMatch> semanticMatches,
		RiskFeatures riskFeatures) {

	/** Empty evidence bundle — used when no context could be assembled. */
	public static StructuredEvidence empty() {
		return new StructuredEvidence(null, null, List.of(), null);
	}

	/**
	 * Exact facts from SQL: point-in-time correct, never invented by the LLM.
	 */
	public record SqlFacts(UUID userId, String userDisplayName, UUID teamId, String teamName, UUID planId,
			LocalDate weekStart, String planState, int capacityBudget, int totalPlannedPoints, int totalAchievedPoints,
			int commitCount, int carryForwardCount, int scopeChangeCount, boolean lockCompliance,
			boolean reconcileCompliance, Map<String, Integer> chessDistribution) {
	}

	/**
	 * A carry-forward lineage chain: ordered list of nodes from origin to current.
	 */
	public record LineageChain(UUID currentCommitId, String currentTitle, int streakLength, List<LineageNode> nodes) {
	}

	/**
	 * A single node in a carry-forward lineage chain.
	 */
	public record LineageNode(UUID commitId, String title, LocalDate weekStart, String outcome, String chessPiece,
			Integer estimatePoints, String carryForwardReason) {
	}

	/**
	 * A semantic match from Pinecone vector retrieval.
	 */
	public record SemanticMatch(String entityType, String entityId, double score, String weekStartDate, String text) {
	}

	/**
	 * Pre-computed risk features from derived read-model tables.
	 */
	public record RiskFeatures(double completionRatio, double avgCompletionRatio4w, int carryForwardStreakMax,
			int scopeChangeCount, int kingCount, int queenCount, List<String> activeRiskSignalTypes) {
	}
}

package com.weeklycommit.ai.service;

import com.fasterxml.jackson.core.JsonProcessingException;
import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.weeklycommit.ai.dto.ManagerAiSummaryResponse;
import com.weeklycommit.ai.provider.AiContext;
import com.weeklycommit.ai.provider.AiProviderRegistry;
import com.weeklycommit.ai.provider.AiSuggestionResult;
import com.weeklycommit.domain.entity.AiSuggestion;
import com.weeklycommit.domain.entity.ManagerReviewException;
import com.weeklycommit.domain.entity.RcdoNode;
import com.weeklycommit.domain.entity.TeamMembership;
import com.weeklycommit.domain.entity.WeeklyCommit;
import com.weeklycommit.domain.entity.WeeklyPlan;
import com.weeklycommit.domain.enums.ChessPiece;
import com.weeklycommit.domain.enums.TicketStatus;
import com.weeklycommit.domain.enums.UserRole;
import com.weeklycommit.domain.repository.ManagerReviewExceptionRepository;
import com.weeklycommit.domain.repository.RcdoNodeRepository;
import com.weeklycommit.domain.repository.TeamMembershipRepository;
import com.weeklycommit.domain.repository.TeamRepository;
import com.weeklycommit.domain.repository.WeeklyCommitRepository;
import com.weeklycommit.domain.repository.WeeklyPlanRepository;
import com.weeklycommit.domain.repository.WorkItemRepository;
import com.weeklycommit.rcdo.exception.ResourceNotFoundException;
import com.weeklycommit.team.exception.AccessDeniedException;
import com.weeklycommit.team.service.AuthorizationService;
import java.time.LocalDate;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;
import java.util.UUID;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

/**
 * Manager team AI summary service (PRD §17 capability 6).
 *
 * <p>
 * Generates a weekly summary citing:
 * <ul>
 * <li>Top RCDO branches by planned commitment.</li>
 * <li>Unresolved manager-review exceptions (cited by id).</li>
 * <li>Carry-forward patterns across team members.</li>
 * <li>Critical blocked items (King/Queen with BLOCKED tickets).</li>
 * </ul>
 *
 * <p>
 * Only visible to managers — access denied for non-managers.
 */
@Service
@Transactional
public class ManagerAiSummaryService {

	private static final Logger log = LoggerFactory.getLogger(ManagerAiSummaryService.class);

	private final AiProviderRegistry registry;
	private final AiSuggestionService suggestionService;
	private final TeamRepository teamRepo;
	private final TeamMembershipRepository membershipRepo;
	private final WeeklyPlanRepository planRepo;
	private final WeeklyCommitRepository commitRepo;
	private final WorkItemRepository workItemRepo;
	private final RcdoNodeRepository rcdoNodeRepo;
	private final ManagerReviewExceptionRepository exceptionRepo;
	private final AuthorizationService authService;
	private final ObjectMapper objectMapper;

	public ManagerAiSummaryService(AiProviderRegistry registry, AiSuggestionService suggestionService,
			TeamRepository teamRepo, TeamMembershipRepository membershipRepo, WeeklyPlanRepository planRepo,
			WeeklyCommitRepository commitRepo, WorkItemRepository workItemRepo, RcdoNodeRepository rcdoNodeRepo,
			ManagerReviewExceptionRepository exceptionRepo, AuthorizationService authService,
			ObjectMapper objectMapper) {
		this.registry = registry;
		this.suggestionService = suggestionService;
		this.teamRepo = teamRepo;
		this.membershipRepo = membershipRepo;
		this.planRepo = planRepo;
		this.commitRepo = commitRepo;
		this.workItemRepo = workItemRepo;
		this.rcdoNodeRepo = rcdoNodeRepo;
		this.exceptionRepo = exceptionRepo;
		this.authService = authService;
		this.objectMapper = objectMapper;
	}

	/**
	 * Returns the AI summary for a team week. Only accessible to managers.
	 *
	 * @param teamId
	 *            the team
	 * @param weekStart
	 *            the week start date
	 * @param callerId
	 *            the requesting user
	 * @return summary response
	 * @throws AccessDeniedException
	 *             if the caller is not a manager/admin
	 * @throws ResourceNotFoundException
	 *             if the team is not found
	 */
	public ManagerAiSummaryResponse getSummary(UUID teamId, LocalDate weekStart, UUID callerId) {
		teamRepo.findById(teamId).orElseThrow(() -> new ResourceNotFoundException("Team not found: " + teamId));

		// Privacy: only managers may access AI summaries
		UserRole callerRole = authService.getCallerRole(callerId);
		if (callerRole != UserRole.ADMIN && callerRole != UserRole.MANAGER) {
			throw new AccessDeniedException("Only managers may view AI team summaries");
		}

		if (!registry.isAiEnabled()) {
			return ManagerAiSummaryResponse.unavailable(teamId, weekStart);
		}

		// Gather team data
		List<TeamMembership> memberships = membershipRepo.findByTeamId(teamId);
		List<WeeklyPlan> plans = planRepo.findByTeamIdAndWeekStartDate(teamId, weekStart);

		// Collect all commits for this team-week
		List<WeeklyCommit> allCommits = new ArrayList<>();
		for (WeeklyPlan plan : plans) {
			allCommits.addAll(commitRepo.findByPlanIdOrderByPriorityOrder(plan.getId()));
		}

		// Derive cited objects: unresolved exceptions
		List<ManagerReviewException> unresolvedExceptions = exceptionRepo
				.findByTeamIdAndWeekStartDateAndResolved(teamId, weekStart, false);
		List<UUID> unresolvedExceptionIds = unresolvedExceptions.stream().map(ManagerReviewException::getId).toList();

		// Carry-forward patterns
		List<String> carryForwardPatterns = deriveCarryForwardPatterns(allCommits);

		// Critical blocked items: King/Queen commits with BLOCKED tickets
		List<UUID> criticalBlockedItemIds = deriveCriticalBlockedItems(allCommits);

		// Top RCDO branches by planned points
		List<String> topRcdoBranches = deriveTopRcdoBranches(allCommits);

		// Build context for AI
		Map<String, Object> additionalCtx = new HashMap<>();
		additionalCtx.put("unresolvedExceptions", unresolvedExceptionIds.size());
		additionalCtx.put("carryForwardPatterns", carryForwardPatterns);
		additionalCtx.put("criticalBlockedItems", criticalBlockedItemIds.size());
		additionalCtx.put("memberCount", memberships.size());
		additionalCtx.put("topRcdoBranches", topRcdoBranches);

		AiContext context = new AiContext(AiContext.TYPE_TEAM_SUMMARY, callerId, null, null, Map.of(),
				Map.of("weekStart", weekStart.toString(), "teamId", teamId.toString()), List.of(), List.of(),
				additionalCtx);

		AiSuggestionResult result = registry.generateSuggestion(context);
		if (!result.available()) {
			return ManagerAiSummaryResponse.unavailable(teamId, weekStart);
		}

		String contextJson = toJson(additionalCtx);
		AiSuggestion stored = suggestionService.storeSuggestion(AiContext.TYPE_TEAM_SUMMARY, callerId, null, null,
				contextJson, result);

		String summaryText = parseSummaryText(result.payload(), memberships.size(), plans.size(), allCommits.size());

		return new ManagerAiSummaryResponse(true, stored.getId(), teamId, weekStart, summaryText, topRcdoBranches,
				unresolvedExceptionIds, carryForwardPatterns, criticalBlockedItemIds, result.modelVersion());
	}

	// -------------------------------------------------------------------------
	// Derived data helpers
	// -------------------------------------------------------------------------

	private List<String> deriveTopRcdoBranches(List<WeeklyCommit> commits) {
		Map<UUID, Integer> pointsByRcdo = new LinkedHashMap<>();
		for (WeeklyCommit c : commits) {
			if (c.getRcdoNodeId() == null) {
				continue;
			}
			int pts = c.getEstimatePoints() != null ? c.getEstimatePoints() : 0;
			pointsByRcdo.merge(c.getRcdoNodeId(), pts, Integer::sum);
		}

		return pointsByRcdo.entrySet().stream().sorted(Map.Entry.<UUID, Integer>comparingByValue().reversed()).limit(3)
				.map(e -> {
					RcdoNode node = rcdoNodeRepo.findById(e.getKey()).orElse(null);
					if (node == null) {
						return e.getKey().toString();
					}
					return node.getTitle() + " (" + e.getValue() + " pts)";
				}).toList();
	}

	private List<String> deriveCarryForwardPatterns(List<WeeklyCommit> commits) {
		long carryForwardCount = commits.stream().filter(c -> c.getCarryForwardStreak() > 0).count();
		if (carryForwardCount == 0) {
			return List.of();
		}
		List<String> patterns = new ArrayList<>();
		patterns.add(carryForwardCount + " commit(s) carried forward this week.");

		long repeatedCount = commits.stream().filter(c -> c.getCarryForwardStreak() >= 2).count();
		if (repeatedCount > 0) {
			patterns.add(repeatedCount + " commit(s) carried forward 2+ consecutive weeks.");
		}
		return patterns;
	}

	private List<UUID> deriveCriticalBlockedItems(List<WeeklyCommit> commits) {
		List<UUID> blocked = new ArrayList<>();
		for (WeeklyCommit c : commits) {
			if (c.getChessPiece() != ChessPiece.KING && c.getChessPiece() != ChessPiece.QUEEN) {
				continue;
			}
			if (c.getWorkItemId() == null) {
				continue;
			}
			workItemRepo.findById(c.getWorkItemId()).filter(wi -> wi.getStatus() == TicketStatus.BLOCKED)
					.ifPresent(wi -> blocked.add(wi.getId()));
		}
		return blocked;
	}

	private String parseSummaryText(String payload, int memberCount, int planCount, int commitCount) {
		try {
			JsonNode node = objectMapper.readTree(payload);
			JsonNode summaryNode = node.get("summaryText");
			if (summaryNode != null && !summaryNode.isNull() && !summaryNode.asText().isBlank()) {
				return summaryNode.asText();
			}
		} catch (JsonProcessingException e) {
			log.debug("Could not parse AI summary text: {}", e.getMessage());
		}
		// Fallback generated summary
		return "Team has " + memberCount + " member(s) with " + planCount + " plan(s) and " + commitCount
				+ " total commit(s) this week.";
	}

	private String toJson(Object obj) {
		try {
			return objectMapper.writeValueAsString(obj);
		} catch (JsonProcessingException e) {
			return "{}";
		}
	}
}

